    #[serde(rename = "boot-disk-size")]
    boot_disk_size: u64,
    /// Controls whether a public IP is assigned/used.
    /// Accepts `"public"` or `"private"` only; defaults to `"private"`.
    #[serde(rename = "ip-address", default)]
